// Promise.race：谁先 settled（fulfilled/rejected），整体就跟谁
const promiseRace = (arr) =>
  new Promise((resolve, reject) => {
    // Promise.resolve：把普通值包成 pending→fulfilled
    for (const p of arr) Promise.resolve(p).then(resolve, reject);
    // 任一先落定都会触发外层；后续结果被忽略（状态不可逆）
  });

// Promise.all：全部 fulfilled 才 resolve；有一项 rejected 就立刻 reject
const promiseAll = (arr) =>
  new Promise((resolve, reject) => {
    const out = [];
    let n = arr.length;
    if (!n) return resolve(out); // 空数组：直接 fulfilled
    arr.forEach((p, i) =>
      Promise.resolve(p).then(
        (v) => {
          out[i] = v;
          if (--n === 0) resolve(out); // 全部 fulfilled
        },
        reject, // 第一个 rejected 传给外层
      ),
    );
  });

// allSettled：单项 rejected 也不让整体 reject；用 Promise.all 包一层
const allSettled = (arr) =>
  Promise.all(
    arr.map((p) =>
      Promise.resolve(p).then(
        (value) => ({ status: 'fulfilled', value }),
        (reason) => ({ status: 'rejected', reason }),
      ),
    ),
  );

// 全部失败时的错误：有 AggregateError 就用规范类型，否则降级为 Error 并挂 errors
const rejAll = (errors) =>
  typeof AggregateError !== 'undefined'
    ? new AggregateError(errors, 'All promises were rejected')
    : Object.assign(new Error('All promises were rejected'), { errors });

const promiseAny = (arr) =>
  new Promise((resolve, reject) => {
    const n = arr.length;
    if (!n) return reject(rejAll([])); // 空数组：立刻算全失败
    let left = n; // 还剩多少项没先结束落定
    const errors = [];
    arr.forEach((p, i) =>
      Promise.resolve(p).then(resolve, (e) => {
        errors[i] = e; // 按下标存失败原因，方便和原顺序对齐
        if (!--left) reject(rejAll(errors)); // 最后一项也失败了才 reject
      }),
    );
  });

// 串行：for...of + await，每次循环会等上一个 await 结束再往下走
const runSeries = async (tasks) => {
  const out = [];
  for (const t of tasks) {
    out.push(await t()); // await 会暂停当前 async 函数，让出线程
  }
  return out;
};

// 重试：try/catch + 递归；attempts 表示还剩几次机会
const retry = async (fn, attempts = 3, delayMs = 0) => {
  try {
    return await fn();
  } catch (e) {
    if (attempts <= 1) throw e; // 机会用完了，原样抛出
    if (delayMs) await new Promise((r) => setTimeout(r, delayMs)); // 两次尝试之间等待
    return retry(fn, attempts - 1, delayMs); // 递归：次数减一再来
  }
};

// 教学示意：只演示 fulfilled 路径；完整版要符合 Promise/A+（thenable 展开等）
class MyPromise {
  constructor(executor) {
    this._state = 'pending'; // 等待中
    this._value = undefined;
    this._cb = [];
    const resolve = (v) => {
      if (this._state !== 'pending') return;
      this._state = 'fulfilled'; // resolve → fulfilled
      this._value = v;
      queueMicrotask(() => this._cb.splice(0).forEach((fn) => fn()));
    };
    try {
      executor(resolve, () => {}); // reject → rejected，此处占位
    } catch (e) { /* 同步 throw → rejected */ }
  }
  then(onFulfilled) {
    return new MyPromise((resolve) => {
      const run = () =>
        resolve(onFulfilled != null ? onFulfilled(this._value) : this._value);
      this._state === 'fulfilled'
        ? queueMicrotask(run)
        : this._cb.push(run); // 仍 pending 则入队
    });
  }
}

// Object.prototype.toString：靠内部类型标签判断，必须用 call 把 this 绑到待测值上
const getType = (x) => Object.prototype.toString.call(x);

// 若题面要 'array' 这种短标签：getType(x).slice(8, -1).toLowerCase()

// myCall：把要调用的函数临时挂到 ctx 上，这样 this 就指向 ctx
Function.prototype.myCall = function (ctx, ...args) {
  const o = ctx == null ? globalThis : Object(ctx); // null/undefined 用全局对象；原始值会装箱
  const k = Symbol('__fn__'); // 唯一键，降低和对象自有属性冲突的概率
  o[k] = this; // 当前函数变成 o 的方法
  try {
    return o[k](...args); // 以方法形式调用，this === o
  } finally {
    delete o[k]; // 无论成功失败都清理临时属性
  }
};

// myApply：第二参是数组或类数组，转成数组后复用 myCall
Function.prototype.myApply = function (ctx, arr) {
  return this.myCall(ctx, ...Array.from(arr ?? []));
};

// myBind：闭包保存原函数 fn 和预设参数 a1
Function.prototype.myBind = function (ctx, ...a1) {
  const fn = this;
  const bound = function (...a2) {
    // new bound() 时 this 是实例，走构造路径；普通调用用绑定的 ctx
    return fn.apply(this instanceof bound ? this : ctx, [...a1, ...a2]);
  };
  // 让 bound 实例能 instanceof 原构造函数：共享原型链
  bound.prototype = Object.create(fn.prototype);
  return bound;
};

// myNew：Ctor 是构造函数，args 是构造参数
const myNew = (Ctor, ...args) => {
  const o = Object.create(Ctor.prototype); // 实例的原型链指向 Ctor.prototype
  const r = Ctor.apply(o, args); // 执行构造函数，可能往 o 上挂属性
  // 规范：只有返回值是对象或函数时才用返回值，否则用 o
  return r != null && (typeof r === 'object' || typeof r === 'function') ? r : o;
};

// instanceof：沿 __proto__ 链查找是否等于 R.prototype
const myInstanceof = (L, R) => {
  const proto = R.prototype; // 右侧构造函数的 prototype
  for (let o = Object.getPrototypeOf(L); o; o = Object.getPrototypeOf(o)) {
    if (o === proto) return true; // 链上某环和目标 prototype 相同
  }
  return false; // 查到 null 还没命中
};

// assign：浅拷贝；后面 source 的同名属性会覆盖前面的
const assign = (target, ...srcs) => {
  const t = Object(target); // 和原生一致：原始类型先包装成对象
  for (const s of srcs) {
    if (s == null) continue; // null / undefined 源直接跳过
    const obj = Object(s);
    for (const k of Object.keys(obj)) {
      // 只遍历可枚举自有字符串键；Symbol 键另题
      t[k] = obj[k];
    }
  }
  return t; // 返回同一个 target 引用
};

// Object.create：借助 new 把实例的原型链设为 proto
const create = (proto) => {
  const F = function () {}; // 空构造函数，只占位
  F.prototype = proto; // 实例将继承 proto 链上的属性
  return new F(); // new 出的对象 __proto__ === proto
};

// 子集 stringify：递归 + 分支；完整版还要处理循环引用（WeakSet）等
const stringify = (v) => {
  if (v === null || typeof v === 'number' || typeof v === 'boolean') return String(v); // null 和原始类型
  if (typeof v === 'string') return JSON.stringify(v); // 自动加引号并转义
  if (Array.isArray(v)) return '[' + v.map(stringify).join(',') + ']'; // 数组元素递归
  return (
    '{' +
    Object.keys(v)
      .map((k) => JSON.stringify(k) + ':' + stringify(v[k])) // 键必须带引号
      .join(',') +
    '}'
  );
};

// 深比较：先 ===（同一引用或严格相等；NaN 需题面单独约定）
const isEqual = (a, b) => {
  if (a === b) return true; // 同一引用或严格相等（NaN 仍不相等）
  if (a == null || b == null || typeof a !== 'object' || typeof b !== 'object') return false;
  const ak = Object.keys(a),
    bk = Object.keys(b);
  if (ak.length !== bk.length) return false; // 可枚举键数量要一致
  return ak.every((k) => k in b && isEqual(a[k], b[k])); // 键名和子值都递归比较
};

// once：闭包记录「是否已执行」和「首次返回值」
const once = (fn) => {
  let done; // 有值表示已经执行过
  let memo; // 缓存首次返回值
  return function (...a) {
    return done ? memo : ((done = 1), (memo = fn.apply(this, a))); // 逗号表达式：先标记再求值
  };
};

// memoize：Map 存「序列化参数 → 结果」
const memoize = (fn) => {
  const c = new Map();
  return function (...a) {
    const k = JSON.stringify(a); // 简单键；键冲突、参数顺序敏感是常见追问
    if (c.has(k)) return c.get(k); // 命中缓存
    const v = fn.apply(this, a);
    c.set(k, v); // 写入缓存
    return v;
  };
};

// 柯里化：fn.length 是形参个数；用 function 才能保留调用时的 this
const curry = (fn) =>
  function curried(...a) {
    if (a.length >= fn.length) return fn.apply(this, a); // 参数凑够了，执行原函数
    return (...b) => curried.apply(this, [...a, ...b]); // 还没够，继续收参
  };

// 链式累加：空调用 () 返回累计和；继续传参则返回同一个累加函数
function createAdder(sum = 0) {
  const add = (n) => {
    if (n === undefined) return sum; // add() 表示结束链，给出结果
    sum += n;
    return add; // add(1)(2) 还能继续调用
  };
  return add;
}
// 示例：const add = createAdder(); add(1)(2)(3)() === 6

// compose：最右边的函数最先处理 x，结果一层层往左传
const compose =
  (...fns) =>
  (x) =>
    fns.reduceRight((v, f) => f(v), x); // 初始累积值是 x

// pipe(...fns)(x) === fns.reduce((v, f) => f(v), x) // 从左到右

// debounce：每次触发都重置定时器，只有停顿满 wait 毫秒才执行
const debounce = (fn, wait) => {
  let t; // 保存定时器 id
  return function (...args) {
    clearTimeout(t); // 新一轮输入，取消上一次「即将执行」
    t = setTimeout(() => fn.apply(this, args), wait); // 保留调用方 this 和参数
  };
};

// 写法一：时间戳版——距上次执行满 wait 才再放行，首次调用会立刻执行
const throttle = (fn, wait) => {
  let prev = 0;
  return function (...args) {
    const now = Date.now();
    if (now - prev >= wait) {
      prev = now; // 记录本次执行时刻
      fn.apply(this, args);
    }
  };
};

// 写法二：定时器版——执行后 wait 内直接忽略，适合「执行完再冷却」
const throttleTimer = (fn, wait) => {
  let t;
  return function (...args) {
    if (t) return; // 还在冷却期
    fn.apply(this, args); // 立刻执行一次
    t = setTimeout(() => {
      t = null; // 冷却结束，允许下一次
    }, wait);
  };
};

// map：按 length 遍历，用 `i in arr` 跳过空洞槽位
const map = (arr, fn, ctx) => {
  const out = [];
  for (let i = 0; i < arr.length; i++) {
    if (i in arr) out[i] = fn.call(ctx, arr[i], i, arr); // 绑定 thisArg，传入当前值、下标、原数组
  }
  return out;
};

// uniqueBy：filter + Map；m.set 在 && 右侧仍会执行，用来「边记边滤」
const uniqueBy = (arr, key) => {
  const m = new Map();
  return arr.filter((o) => !m.has(o[key]) && m.set(o[key], true)); // 第一次见到的 key 才保留
};

// flatten：仍是数组且剩余深度 > 0 就继续递归，否则当作叶子元素
const flatten = (arr, d = Infinity) =>
  arr.flatMap((v) =>
    Array.isArray(v) && d > 0 ? flatten(v, d - 1) : [v],
  );

// listToTree：Map 存 id → 带 children 的节点；reduce 挂父子关系
const listToTree = (list) => {
  const m = new Map(list.map((n) => [n.id, { ...n, children: [] }])); // 复制数据并初始化 children
  return list.reduce((roots, n) => {
    const node = m.get(n.id);
    const p = m.get(n.parentId); // 找不到父节点就视为根
    (p ? p.children : roots).push(node); // 有父挂子树，无父进 roots
    return roots;
  }, []);
};

// treeToList：深度优先遍历；解构把子节点从 rest 里剥离
const treeToList = (nodes, k = 'children') => {
  const out = [];
  const walk = (n) => {
    if (!n) return;
    const { [k]: ch, ...rest } = n; // rest 是不含 children 的浅拷贝字段
    out.push(rest);
    (ch ?? []).forEach(walk); // 递归子树
  };
  [].concat(nodes).forEach(walk); // 兼容单根或森林
  return out;
};

// JSON.parse(JSON.stringify)：写法简单，但丢类型、不能处理循环引用
// 递归 + WeakMap：在对象图上深拷贝，避免环导致栈溢出
const clone = (x, seen = new WeakMap()) => {
  if (x == null || typeof x !== 'object') return x; // 原始值或 null
  if (seen.has(x)) return seen.get(x); // 遇到环：返回已经建好的副本
  if (Array.isArray(x)) {
    const a = [];
    seen.set(x, a); // 先登记，再递归填槽，处理自引用数组
    x.forEach((v, i) => (a[i] = clone(v, seen)));
    return a;
  }
  const o = {};
  seen.set(x, o);
  for (const k of Object.keys(x)) o[k] = clone(x[k], seen); // 只拷贝自有可枚举字符串键
  return o;
};

// EventEmitter：Map<事件名, Set<回调>>
class EventEmitter {
  constructor() {
    this._m = new Map();
  }
  on(ev, fn) {
    const s = this._m.get(ev) ?? new Set(); // 没有就新建监听集合
    s.add(fn);
    this._m.set(ev, s);
    return this; // 支持链式调用
  }
  off(ev, fn) {
    this._m.get(ev)?.delete(fn);
    return this;
  }
  emit(ev, ...args) {
    const s = this._m.get(ev);
    if (!s || !s.size) return false; // 没有监听
    [...s].forEach((fn) => fn(...args)); // 先快照再遍历，避免回调里改 Set 破坏遍历
    return true;
  }
}

// 冒泡：每轮把当前未排序区间的最大元素「冒」到右端；swapped 优化已有序的情况
const bubbleSort = (arr) => {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    let swapped = false;
    for (let j = 0; j < i; j++) {
      if (a[j] > a[j + 1]) {
        [a[j], a[j + 1]] = [a[j + 1], a[j]]; // 解构交换
        swapped = true;
      }
    }
    if (!swapped) break; // 一轮没交换说明已有序，提前结束
  }
  return a;
};

// 选择排序：每轮把区间里最小值换到左端 i
const selectionSort = (arr) => {
  const a = [...arr];
  for (let i = 0; i < a.length; i++) {
    let min = i; // 先假设 i 是最小
    for (let j = i + 1; j < a.length; j++) if (a[j] < a[min]) min = j; // 扫描找更小下标
    if (min !== i) [a[i], a[min]] = [a[min], a[i]]; // 不一样才交换
  }
  return a;
};

// 插入排序：把 a[i] 插入到左侧已有序段的正确位置
const insertionSort = (arr) => {
  const a = [...arr];
  for (let i = 1; i < a.length; i++) {
    const x = a[i]; // 待插入元素
    let j = i;
    while (j > 0 && a[j - 1] > x) {
      a[j] = a[j - 1]; // 比 x 大的元素整体右移一格
      j--;
    }
    a[j] = x; // 空出的位置放入 x
  }
  return a;
};

// 三路快排（非原地）：好写；和 Lomuto/Hoare 原地 partition 写法不同
const quickSort = (arr) => {
  if (arr.length <= 1) return arr; // 递归终止
  const p = arr[0]; // 基准值；工程里常随机选
  const left = [],
    mid = [],
    right = [];
  for (const x of arr) {
    if (x < p) left.push(x);
    else if (x > p) right.push(x);
    else mid.push(x); // 和 pivot 相等的放中间，缓解全相等时的退化
  }
  return [...quickSort(left), ...mid, ...quickSort(right)];
};

// 默认 sort：按字符串排，[10, 2, 1].sort() 会得到 [1, 10, 2]
// 数值升序：(a, b) => a - b；返回值正负决定顺序，0 表示相等
// 原地排序：先 [...arr] 再 sort 可避免改原数组
const sortAsc = (arr) => [...arr].sort((a, b) => a - b);

// 对象数组：users.sort((a, b) => a.age - b.age)
// 稳定性：ES2019 起规范要求稳定排序；老引擎以实际为准
